sketch is not working because i cannot import the instantsearch library. However, i reduced the code and added screenshots for reference. I hope this makes sense.

```js
import React, { Component } from 'react';
import { TouchableOpacity, TouchableHighlight, Image, Text, TextInput, Dimensions, Title, Icon, Header, View,  StyleSheet, Modal, ScrollView, ListView, RefreshControl } from 'react-native';


// Algolia Instantsearch
import { InstantSearch } from 'react-instantsearch/native';
import { connectSearchBox, connectInfiniteHits, connectCurrentRefinements, connectStats, connectHierarchicalMenu, connectMultiRange, connectRefinementList } from 'react-instantsearch/connectors';

// Catalog components
import Hits from './hits';

// Modal Content
import CurrentRefinements from './currentrefinements';
import CategoryFilter from './categoryfilter';
import SizeFilter from './sizefilter';
import ApplyFilter from './applyfilter';

// Pass Components to Algolia Connectors
const ConnectedHits = connectInfiniteHits(Hits);
const ConnectedCurrentRefinements = connectCurrentRefinements(CurrentRefinements);
const ConnectedCategoryFilter = connectHierarchicalMenu(CategoryFilter);
const ConnectedSizeFilter = connectRefinementList(SizeFilter);
const ConnectedApplyFilter=  connectStats(ApplyFilter);
 

// Main Component
class InstaSearch extends Component {

  constructor(props) {
    super(props);

    this.state  = {
      filterModalOpen : false,
    }
  }

  toggleFilterModal() {
      this.setState( prevState => ({
          filterModalOpen : !prevState.filterModalOpen
      }));
  }
   
  render() {

    const { filterModalOpen } = this.state;
 
    return (

      <View>
          <InstantSearch
            appId="latency"
            apiKey="6be0576ff61c053d5f9a3225e2a90f76"
            indexName='ikea'
          >

            <TestStats />

            <TouchableOpacity onPress = { this.toggleFilterModal.bind(this) } >
              <Text> Open Filter Modal </Text>
            </TouchableOpacity>

            <Modal
                animationType={"slide"}
                transparent={false}
                visible={filterModalOpen}
                > 
           
                <View style = {{ flex : 1 }}>
                    <ConnectedCurrentRefinements  />
                    <ConnectedCategoryFilter attributes = {['category']} />
                    <ConnectedSizeFilter attributeName = "sizes"  />
                    <ConnectedApplyFilter toggleFilterModal = {this.toggleFilterModal.bind(this)} />
                </View>
            </Modal>


              <ConnectedHits/> 

          </InstantSearch>
      </View>
      );
  }
}

const TestStats = connectStats( ({nbHits }) => {
  return (
    <Text> {nbHits} </Text>
  );
});

 

export default InstaSearch;
```

